class Solution {
    public long repairCars(int[] ranks, int cars) {
        long res = Long.MAX_VALUE;
        for (int rank : ranks) {
            long time = 0;
            int remaining = cars;
            for (int i = 1; ; i++) {
                time += rank * i * i;
                remaining -= i;
                if (remaining <= 0) break;
            }
            res = Math.min(res, time);
        }
        return res;
    }
}

